head.script:
{
  "@context": "https://schema.org",
  "@type": "WebSite",
  "name": "مصمم متاجر سلة و زد ورمز",
  "url": "https://www.salla1zid.com/",
  "description": "نقدم خدمات تصميم وتطوير متاجر سلة وزد ورمز، تخصيص CSS احترافي، أكواد خصم حصرية، وأدوات مفتوحة المصدر لنجاح متجرك الإلكتروني.",
  "inLanguage": "ar",
  "author": {
    "@type": "Person",
    "name": "Ali Ahmed"
  }
}

head.b:skin:
/* ============================================================
   قالب بلوجر احترافي | مصمم متاجر سلة و زد ورمز
   Ali Ahmed - salla1zid
   تصميم حصري ومبتكر - جميع الحقوق محفوظة
   ============================================================ */

/* ===== CSS Variables & Theme System ===== */
:root {
  --primary: #5e3bee;
  --primary-dark: #4a2fbe;
  --primary-light: #7d56f9;
  --primary-gradient: linear-gradient(135deg, #5e3bee 0%, #7d56f9 100%);
  --secondary: #8b5cf6;
  --secondary-gradient: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
  --accent: #4facfe;
  --accent-gradient: linear-gradient(135deg, #4facfe 0%, #00f2fe 100%);
  --text: #2d3748;
  --text-light: #718096;
  --text-muted: #a0aec0;
  --bg: #ffffff;
  --bg-alt: #f8faff;
  --card-bg: #ffffff;
  --border: #e2e8f0;
  --primary-rgb: 94, 59, 238;
  --secondary-purple: #8b5cf6;
  --radius: 12px;
  --radius-lg: 20px;
  --radius-full: 50px;
  --shadow: 0 4px 20px rgba(94, 59, 238, 0.1);
  --shadow-hover: 0 12px 40px rgba(94, 59, 238, 0.2);
  --transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
  --ease-out-quart: cubic-bezier(0.25, 1, 0.5, 1);
  --ease-out-quint: cubic-bezier(0.22, 1, 0.36, 1);
  --ease-out-expo: cubic-bezier(0.16, 1, 0.3, 1);
  --header-bg: rgba(65, 47, 144, 0.2);
}

[data-theme="dark"] {
  --primary: #a78bfa;
  --primary-light: #c4b5fd;
  --primary-gradient: linear-gradient(135deg, #8b5cf6 0%, #a78bfa 100%);
  --secondary: #c4b5fd;
  --secondary-gradient: linear-gradient(135deg, #8b5cf6 0%, #a78bfa 100%);
  --accent: #a78bfa;
  --text: #f1f5f9;
  --text-light: #cbd5e1;
  --text-muted: #94a3b8;
  --bg: #0f0f1a;
  --bg-alt: #1a1a2e;
  --card-bg: #1a1a2e;
  --border: #2d2d44;
  --primary-rgb: 167, 139, 250;
  --secondary-purple: #a78bfa;
  --shadow: 0 4px 20px rgba(139, 92, 246, 0.15);
  --shadow-hover: 0 12px 40px rgba(139, 92, 246, 0.25);
  --header-bg: rgba(20, 16, 42, 0.95);
}

/* ===== Base ===== */
* { margin: 0; padding: 0; box-sizing: border-box; }
html { scroll-behavior: smooth; }
body {
  font-family: 'Tajawal', sans-serif !important;
  line-height: 1.6;
  color: var(--text);
  background: var(--bg);
  direction: rtl;
  text-align: right;
  overflow-x: hidden;
  transition: background 0.3s ease, color 0.3s ease;
}
a { text-decoration: none; color: var(--primary); transition: var(--transition); }
a:hover { color: var(--secondary); }
ul { list-style: none; }
img { max-width: 100%; height: auto; }
.container {
  width: 100%;
  max-width: 1200px;
  margin: 0 auto;
  padding: 0 20px;
}
::selection { background: var(--primary); color: white; }

/* ===== Scrollbar ===== */
::-webkit-scrollbar { width: 10px; }
::-webkit-scrollbar-track { background: var(--bg-alt); }
::-webkit-scrollbar-thumb { background: var(--primary-gradient); border-radius: 5px; }

/* ===== Header ===== */
.header {
  position: fixed;
  top: 20px;
  left: 50%;
  transform: translateX(-50%);
  width: 90%;
  max-width: 1200px;
  z-index: 1000;
  padding: 10px 20px;
  border-radius: 50px;
}
.header::before {
  content: '';
  position: absolute;
  inset: 0;
  background: var(--header-bg);
  backdrop-filter: blur(20px);
  -webkit-backdrop-filter: blur(20px);
  border-radius: 50px;
  z-index: -1;
}
.header.scrolled { top: 15px; padding: 8px 20px; }
.header-content {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 20px;
}
.logo a {
  font-size: 1.5rem;
  font-weight: 800;
  color: white;
  background: var(--primary-gradient);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}
[data-theme="light"] .logo a { color: var(--primary); }
.nav-links { display: flex; gap: 8px; }
.nav-links li a {
  color: white;
  font-weight: 500;
  padding: 8px 16px;
  border-radius: 50px;
  font-size: 0.9rem;
  transition: var(--transition);
  position: relative;
}
.nav-links li a:hover,
.nav-links li a.active {
  background: rgba(255,255,255,0.15);
  color: white;
  transform: translateY(-2px);
}
[data-theme="light"] .nav-links li a { color: #333; }
[data-theme="light"] .nav-links li a:hover,
[data-theme="light"] .nav-links li a.active {
  background: var(--primary-gradient);
  color: white;
}
.header-actions { display: flex; align-items: center; gap: 12px; }
.theme-toggle {
  width: 36px; height: 36px;
  border-radius: 50%;
  background: rgba(255,255,255,0.1);
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: var(--transition);
  border: none;
  font-size: 1.1rem;
  color: white;
}
[data-theme="light"] .theme-toggle { color: #333; background: rgba(0,0,0,0.05); }
.theme-toggle:hover { transform: scale(1.1); }
.mobile-toggle {
  display: none;
  width: 36px; height: 36px;
  border-radius: 50%;
  background: rgba(255,255,255,0.1);
  cursor: pointer;
  align-items: center;
  justify-content: center;
  border: none;
  font-size: 1.2rem;
  color: white;
}
[data-theme="light"] .mobile-toggle { color: #333; }
.header-whatsapp-btn {
  display: flex;
  align-items: center;
  gap: 8px;
  background: #25D366;
  color: white !important;
  padding: 8px 18px;
  border-radius: 50px;
  font-weight: 600;
  font-size: 0.85rem;
  transition: var(--transition);
}
.header-whatsapp-btn:hover { transform: translateY(-2px); box-shadow: 0 5px 15px rgba(37,211,102,0.4); }

/* ===== Mobile Menu ===== */
@media (max-width: 992px) {
  .nav {
    position: fixed;
    top: 0; right: -100%;
    width: 280px; max-width: 85%;
    height: 100vh;
    background: linear-gradient(135deg, rgba(65,47,144,0.98), rgba(138,125,219,0.95));
    backdrop-filter: blur(20px);
    box-shadow: -10px 0 40px rgba(0,0,0,0.4);
    transition: right 0.4s cubic-bezier(0.4,0,0.2,1);
    padding: 100px 30px 40px;
    z-index: 999;
    overflow-y: auto;
  }
  .nav.active { right: 0; }
  .nav-links { flex-direction: column; gap: 5px; }
  .nav-links li a { display: block; padding: 14px 20px; border-radius: 12px; font-size: 1rem; }
  .mobile-toggle { display: flex !important; }
  .header { width: 95%; padding: 8px 15px; }
  .header-whatsapp-btn span { display: none; }
}

/* ===== Focus & Accessibility ===== */
*:focus-visible {
  outline: 2px solid var(--primary);
  outline-offset: 2px;
  border-radius: 4px;
}
button:focus-visible, a:focus-visible { outline-offset: 3px; }

/* ===== Card Hover Refinements ===== */
.service-card, .help-card, .discount-card, .store-link-card, .blog-post-card {
  transition: transform 0.4s var(--ease-out-quart), box-shadow 0.4s var(--ease-out-quart), border-color 0.3s ease;
}
.service-card:hover, .help-card:hover {
  transform: translateY(-6px);
  box-shadow: var(--shadow-hover);
}

/* ===== Section Title Polish ===== */
.section-title {
  text-align: center;
  margin-bottom: 50px;
  position: relative;
}
.section-title h2 {
  font-size: 2.2rem;
  font-weight: 800;
  color: var(--text);
  margin-bottom: 12px;
  position: relative;
  display: inline-block;
}
.section-title h2::after {
  content: '';
  display: block;
  width: 60px;
  height: 4px;
  background: var(--primary-gradient);
  border-radius: 2px;
  margin: 12px auto 0;
}
.section-title p {
  color: var(--text-light);
  font-size: 1.05rem;
  max-width: 600px;
  margin: 0 auto;
  line-height: 1.7;
}

/* ===== Hero Section ===== */
.hero-section {
  position: relative;
  min-height: 85vh;
  display: flex;
  align-items: center;
  justify-content: center;
  text-align: center;
  overflow: hidden;
  background: linear-gradient(135deg, #1a1040 0%, #2d1b69 50%, #1a1040 100%);
  padding: 120px 0 60px;
}
[data-theme="light"] .hero-section { background: linear-gradient(135deg, #f0edff 0%, #e8e0ff 50%, #f0edff 100%); }
.hero-particles {
  position: absolute;
  inset: 0;
  overflow: hidden;
  pointer-events: none;
}
.hero-particle {
  position: absolute;
  width: 6px; height: 6px;
  background: rgba(139,92,246,0.3);
  border-radius: 50%;
  animation: floatParticle 20s infinite;
}
@keyframes floatParticle {
  0%, 100% { transform: translateY(0) translateX(0); opacity: 0; }
  10% { opacity: 1; }
  90% { opacity: 1; }
  100% { transform: translateY(-100vh) translateX(100px); opacity: 0; }
}
.hero-content { max-width: 800px; position: relative; z-index: 1; }
.hero-badge {
  display: inline-block;
  background: rgba(255,255,255,0.1);
  color: white;
  padding: 10px 24px;
  border-radius: 50px;
  font-size: 0.9rem;
  margin-bottom: 20px;
  backdrop-filter: blur(5px);
  animation: fadeInUp 1s ease-out;
}
[data-theme="light"] .hero-badge { background: rgba(94,59,238,0.1); color: var(--primary); font-weight: 700; }
.hero-content h1 {
  font-size: 3.5rem;
  font-weight: 800;
  color: white;
  margin-bottom: 20px;
  line-height: 1.2;
  animation: fadeInUp 1s ease-out 0.2s both;
}
[data-theme="light"] .hero-content h1 {
  background: linear-gradient(135deg, #412f90 0%, #6c63ff 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}
.hero-content p {
  font-size: 1.2rem;
  color: rgba(255,255,255,0.9);
  margin-bottom: 30px;
  max-width: 600px;
  margin-left: auto;
  margin-right: auto;
  animation: fadeInUp 1s ease-out 0.4s both;
}
[data-theme="light"] .hero-content p { color: #4a5568; }
.hero-btn {
  display: inline-flex;
  align-items: center;
  gap: 10px;
  background: linear-gradient(135deg, #8a7ddb 0%, #6c63ff 100%);
  color: white;
  padding: 16px 36px;
  border-radius: 50px;
  font-weight: 700;
  font-size: 1.1rem;
  transition: var(--transition);
  box-shadow: 0 4px 15px rgba(108,99,255,0.3);
  animation: fadeInUp 1s ease-out 0.6s both;
}
.hero-btn:hover { transform: translateY(-3px); box-shadow: 0 8px 25px rgba(108,99,255,0.5); color: white; }

/* ===== Animations ===== */
@keyframes fadeInUp {
  from { opacity: 0; transform: translateY(30px); }
  to { opacity: 1; transform: translateY(0); }
}
@keyframes slideUp {
  to { opacity: 1; transform: translateY(0); }
}

/* ===== Section Common ===== */
.section { padding: 80px 0; }
.section-title { text-align: center; margin-bottom: 50px; }
.section-title h2 {
  font-size: 2.5rem;
  font-weight: 800;
  background: var(--primary-gradient);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  margin-bottom: 15px;
}
.section-title p { color: var(--text-light); max-width: 600px; margin: 0 auto; font-size: 1.1rem; }

/* ===== Services ===== */
.services-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(260px, 1fr));
  gap: 30px;
  margin-top: 50px;
}
.service-card {
  background: var(--card-bg);
  border-radius: 24px;
  padding: 40px 30px;
  text-align: center;
  position: relative;
  overflow: hidden;
  box-shadow: var(--shadow);
  transition: all 0.4s cubic-bezier(0.175, 0.885, 0.32, 1.275);
  border: 1px solid var(--border);
}
.service-card::before {
  content: '';
  position: absolute;
  top: 0; left: 0; right: 0;
  height: 5px;
  background: var(--primary-gradient);
  transform: scaleX(0);
  transition: transform 0.3s ease;
}
.service-card:hover { transform: translateY(-12px); box-shadow: var(--shadow-hover); }
.service-card:hover::before { transform: scaleX(1); }
.service-icon {
  width: 70px; height: 70px;
  margin: 0 auto 20px;
  border-radius: 18px;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 1.8rem;
  background: var(--primary-gradient);
  color: white;
  box-shadow: var(--shadow);
  transition: var(--transition);
}
.service-card:hover .service-icon { transform: scale(1.1) rotate(5deg); }
.service-card h3 { font-size: 1.3rem; color: var(--primary); margin-bottom: 12px; }
.service-card p { color: var(--text-light); font-size: 0.95rem; line-height: 1.7; }
.service-features { text-align: right; margin: 20px 0; padding: 0; }
.service-features li {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 8px 0;
  font-size: 0.9rem;
  color: var(--text);
  border-bottom: 1px solid var(--border);
}
.service-features li:last-child { border-bottom: none; }

/* ===== Stats ===== */
.stats-section {
  padding: 80px 0;
  background: var(--bg-alt);
  position: relative;
}
.stats-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));
  gap: 30px;
}
.stat-item {
  background: var(--card-bg);
  border-radius: 20px;
  padding: 35px 20px;
  text-align: center;
  box-shadow: var(--shadow);
  transition: var(--transition);
  border: 1px solid var(--border);
  animation: slideUp 0.6s ease-out forwards;
  opacity: 0;
  transform: translateY(30px);
}
.stat-item:nth-child(1) { animation-delay: 0.1s; }
.stat-item:nth-child(2) { animation-delay: 0.2s; }
.stat-item:nth-child(3) { animation-delay: 0.3s; }
.stat-item:nth-child(4) { animation-delay: 0.4s; }
.stat-item:hover { transform: translateY(-10px); box-shadow: var(--shadow-hover); }
.stat-icon {
  width: 65px; height: 65px;
  margin: 0 auto 18px;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 1.8rem;
  background: rgba(var(--primary-rgb), 0.1);
  color: var(--primary);
  transition: var(--transition);
}
.stat-item:hover .stat-icon { transform: scale(1.1); background: var(--primary-gradient); color: white; }
.stat-number {
  font-size: 2.8rem;
  font-weight: 800;
  background: var(--primary-gradient);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  margin-bottom: 8px;
}
.stat-label { font-size: 1rem; color: var(--text-light); font-weight: 600; }

/* ===== About ===== */
.about-section-centered {
  padding: 80px 0;
  background: var(--bg);
  position: relative;
}
.about-content-centered {
  max-width: 750px;
  margin: 0 auto;
  text-align: center;
  padding: 40px;
  background: var(--card-bg);
  border-radius: 20px;
  box-shadow: var(--shadow);
}
.about-icon-centered {
  width: 75px; height: 75px;
  margin: 0 auto 20px;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 2rem;
  background: var(--primary-gradient);
  color: white;
  box-shadow: 0 10px 20px rgba(var(--primary-rgb), 0.3);
}
.about-content-centered h2 {
  font-size: 2.2rem;
  margin-bottom: 15px;
  color: var(--primary);
}
.about-content-centered p { font-size: 1.05rem; line-height: 1.8; color: var(--text); max-width: 600px; margin: 0 auto; }
.about-actions-centered { display: flex; justify-content: center; gap: 15px; margin-top: 25px; }

/* ===== Buttons ===== */
.btn, .btn-primary-glow {
  display: inline-flex;
  align-items: center;
  gap: 10px;
  padding: 14px 30px;
  border-radius: 50px;
  font-weight: 700;
  font-size: 1rem;
  transition: var(--transition);
  border: none;
  cursor: pointer;
  text-decoration: none;
  background: var(--primary-gradient);
  color: white;
  box-shadow: 0 10px 20px rgba(var(--primary-rgb), 0.3);
}
.btn:hover, .btn-primary-glow:hover {
  transform: translateY(-3px);
  box-shadow: 0 15px 30px rgba(var(--primary-rgb), 0.4);
  color: white;
}
.btn-outline-glow {
  background: transparent;
  color: var(--primary);
  border: 2px solid var(--primary);
  padding: 12px 28px;
  border-radius: 50px;
  font-weight: 700;
  font-size: 1rem;
  transition: var(--transition);
  text-decoration: none;
  display: inline-flex;
  align-items: center;
  gap: 10px;
}
.btn-outline-glow:hover {
  background: var(--primary-gradient);
  color: white;
  border-color: transparent;
  transform: translateY(-3px);
}

/* ===== Testimonials ===== */
.testimonials-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(300px, 1fr));
  gap: 30px;
  margin-top: 50px;
}
.testimonial-card {
  background: var(--card-bg);
  border-radius: 20px;
  padding: 30px;
  box-shadow: var(--shadow);
  border: 1px solid var(--border);
  transition: var(--transition);
  display: flex;
  flex-direction: column;
}
.testimonial-card:hover { transform: translateY(-8px); box-shadow: var(--shadow-hover); }
.testimonial-content { flex: 1; margin-bottom: 20px; }
.testimonial-content p {
  font-style: italic;
  color: var(--text);
  line-height: 1.8;
  font-size: 0.95rem;
}
.testimonial-content p::before { content: '"'; font-size: 1.5rem; color: var(--primary); }
.testimonial-content p::after { content: '"'; font-size: 1.5rem; color: var(--primary); }
.testimonial-author { display: flex; align-items: center; gap: 15px; }
.author-image {
  width: 55px; height: 55px;
  border-radius: 50%;
  overflow: hidden;
  border: 3px solid var(--primary);
  background: var(--bg-alt);
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 1.5rem;
  color: var(--primary);
}
.testimonial-author h4 { font-size: 1rem; color: var(--primary); }

/* ===== Partners ===== */
.partners-section {
  padding: 80px 0;
  background: var(--bg-alt);
  position: relative;
  overflow: hidden;
}
.partners-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(130px, 1fr));
  gap: 20px;
  margin-top: 40px;
}
.partner-logo {
  background: var(--card-bg);
  border-radius: 12px;
  padding: 20px;
  display: flex;
  align-items: center;
  justify-content: center;
  height: 90px;
  box-shadow: var(--shadow);
  transition: var(--transition);
  border: 1px solid var(--border);
}
.partner-logo:hover { transform: translateY(-5px); box-shadow: var(--shadow-hover); }
.partner-logo span {
  font-size: 0.8rem;
  color: var(--text-muted);
  font-weight: 600;
  text-align: center;
}

/* ===== Portfolio Gallery ===== */
.portfolio-slider-section { padding: 80px 0; overflow: hidden; }
.portfolio-scroll {
  display: flex;
  gap: 20px;
  overflow-x: auto;
  padding: 20px 0;
  scroll-snap-type: x mandatory;
  -webkit-overflow-scrolling: touch;
  scroll-behavior: smooth;
  cursor: grab;
}
.portfolio-scroll:active { cursor: grabbing; }
.portfolio-scroll::-webkit-scrollbar { height: 6px; }
.portfolio-scroll::-webkit-scrollbar-track { background: var(--bg-alt); border-radius: 3px; }
.portfolio-scroll::-webkit-scrollbar-thumb { background: var(--primary-gradient); border-radius: 3px; }
.portfolio-item-snap {
  flex: 0 0 300px;
  height: 280px;
  border-radius: 20px;
  overflow: hidden;
  scroll-snap-align: start;
  box-shadow: var(--shadow);
  transition: transform 0.4s var(--ease-out-quart), box-shadow 0.4s var(--ease-out-quart);
  position: relative;
  cursor: pointer;
  border: 1px solid var(--border);
}
.portfolio-item-snap:focus-visible { outline: 2px solid var(--primary); outline-offset: 3px; }
.portfolio-item-snap:hover { transform: translateY(-8px) scale(1.02); box-shadow: var(--shadow-hover); }
.portfolio-item-snap .mockup-browser {
  width: 100%;
  height: 100%;
  display: flex;
  flex-direction: column;
  position: relative;
}
.portfolio-item-snap .mockup-bar {
  height: 24px;
  display: flex;
  align-items: center;
  gap: 5px;
  padding: 0 12px;
}
.portfolio-item-snap .mockup-dot {
  width: 7px; height: 7px;
  border-radius: 50%;
}
.portfolio-item-snap .mockup-url {
  font-size: 0.6rem;
  color: rgba(255,255,255,0.7);
  margin-right: auto;
  direction: ltr;
  text-align: left;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  max-width: 160px;
}
.portfolio-item-snap .mockup-content {
  flex: 1;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  padding: 15px;
  text-align: center;
  position: relative;
  transition: transform 0.4s var(--ease-out-quart);
}
.portfolio-item-snap .mockup-icon { font-size: 2.5rem; margin-bottom: 8px; transition: transform 0.3s var(--ease-out-quart); }
.portfolio-item-snap .mockup-title {
  font-size: 0.85rem;
  font-weight: 700;
  color: rgba(255,255,255,0.95);
}
.portfolio-item-snap .mockup-desc {
  font-size: 0.65rem;
  color: rgba(255,255,255,0.6);
  margin-top: 3px;
}
.portfolio-item-snap:hover .mockup-content { transform: scale(1.04); }
.portfolio-item-snap:hover .mockup-icon { transform: scale(1.15); }
.portfolio-item-snap:active { transform: translateY(-4px) scale(0.98); }
.portfolio-item-snap img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  transition: transform 0.5s var(--ease-out-quart);
}
.portfolio-item-snap:hover img { transform: scale(1.1); }
.portfolio-item-snap .overlay {
  position: absolute;
  bottom: 0; left: 0; right: 0;
  padding: 20px;
  background: linear-gradient(to top, rgba(0,0,0,0.85), transparent);
  color: white;
  opacity: 0;
  transition: opacity 0.3s var(--ease-out-quart);
  pointer-events: none;
}
.portfolio-item-snap:hover .overlay { opacity: 1; }
.portfolio-item-snap .overlay h4 { font-size: 1rem; margin-bottom: 5px; }
.portfolio-item-snap .overlay a {
  color: var(--primary-light);
  font-size: 0.85rem;
  display: flex;
  align-items: center;
  gap: 5px;
  pointer-events: auto;
}
.portfolio-item-snap .overlay a:focus-visible { outline: 2px solid white; outline-offset: 2px; border-radius: 4px; }

/* ===== Toast Notification ===== */
.copy-toast {
  position: fixed;
  bottom: 30px;
  left: 50%;
  transform: translateX(-50%) translateY(100px);
  background: linear-gradient(135deg, #10B981, #059669);
  color: white;
  padding: 15px 30px;
  border-radius: 50px;
  box-shadow: 0 10px 30px rgba(16, 185, 129, 0.4);
  z-index: 9999;
  opacity: 0;
  transition: all 0.4s var(--ease-out-quart);
  pointer-events: none;
  white-space: nowrap;
  font-weight: 600;
}
.copy-toast.show {
  opacity: 1;
  transform: translateX(-50%) translateY(0);
}

/* ===== Button Outline Glow ===== */
.btn-outline-glow {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  padding: 12px 28px;
  border-radius: 50px;
  background: transparent;
  color: var(--primary);
  border: 2px solid var(--primary);
  font-weight: 700;
  font-size: 0.95rem;
  cursor: pointer;
  transition: all 0.4s var(--ease-out-quart);
  text-decoration: none;
  position: relative;
}
.btn-outline-glow:hover {
  background: var(--primary-gradient);
  color: white;
  border-color: transparent;
  box-shadow: 0 5px 20px rgba(var(--primary-rgb), 0.3);
  transform: translateY(-2px);
}
.btn-outline-glow:active { transform: translateY(0) scale(0.98); }

/* ===== Primary Glow Button ===== */
.btn-primary-glow {
  display: inline-flex;
  align-items: center;
  gap: 10px;
  padding: 14px 32px;
  border-radius: 50px;
  background: var(--primary-gradient);
  color: white;
  font-weight: 700;
  font-size: 1rem;
  border: none;
  cursor: pointer;
  transition: all 0.4s var(--ease-out-quart);
  text-decoration: none;
  box-shadow: 0 5px 20px rgba(var(--primary-rgb), 0.25);
}
.btn-primary-glow:hover {
  transform: translateY(-3px);
  box-shadow: 0 8px 30px rgba(var(--primary-rgb), 0.4);
  color: white;
}
.btn-primary-glow:active { transform: translateY(0) scale(0.97); }

/* ===== Store Links ===== */
.stores-section { padding: 80px 0; }
.stores-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(180px, 1fr));
  gap: 15px;
  margin-bottom: 30px;
}
.store-link-card {
  display: flex;
  flex-direction: column;
  align-items: center;
  padding: 20px 12px;
  background: var(--card-bg);
  border-radius: var(--radius-lg);
  border: 2px solid var(--border);
  text-decoration: none;
  transition: var(--transition);
  position: relative;
  overflow: hidden;
}
.store-link-card::before {
  content: '';
  position: absolute;
  top: 0; left: 0; right: 0;
  height: 4px;
  background: var(--primary-gradient);
  transform: scaleX(0);
  transition: transform 0.3s ease;
}
.store-link-card:hover { transform: translateY(-6px); border-color: var(--primary); box-shadow: var(--shadow-hover); }
.store-link-card:hover::before { transform: scaleX(1); }
.store-link-card .store-icon {
  width: 50px; height: 50px;
  border-radius: 50%;
  background: rgba(var(--primary-rgb), 0.1);
  display: flex;
  align-items: center;
  justify-content: center;
  margin-bottom: 10px;
  font-size: 1.3rem;
  color: var(--primary);
  transition: var(--transition);
}
.store-link-card:hover .store-icon { background: var(--primary-gradient); color: white; transform: scale(1.1); }
.store-link-card .store-name { font-size: 0.95rem; font-weight: 700; color: var(--text); margin-bottom: 3px; }
.store-link-card .store-url { font-size: 0.75rem; color: var(--text-light); direction: ltr; }
.stores-actions { display: flex; justify-content: center; gap: 15px; flex-wrap: wrap; }
.action-btn {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  padding: 12px 24px;
  border-radius: 50px;
  font-weight: 700;
  font-size: 0.95rem;
  cursor: pointer;
  transition: var(--transition);
  border: none;
  text-decoration: none;
}
.copy-all-btn { background: var(--primary-gradient); color: white; box-shadow: 0 5px 15px rgba(var(--primary-rgb),0.3); }
.share-whatsapp-btn { background: linear-gradient(135deg,#25D366 0%,#128C7E 100%); color: white; }
.view-gallery-btn { background: var(--card-bg); color: var(--primary); border: 2px solid var(--primary); }
.action-btn:hover { transform: translateY(-3px); color: white; }
.view-gallery-btn:hover { background: var(--primary); color: white; }

/* ===== Discount Coupons ===== */
.discounts-section { padding: 80px 0; background: var(--bg-alt); }
.discounts-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(280px, 1fr));
  gap: 25px;
  margin-top: 40px;
}
.discount-card {
  background: var(--card-bg);
  border-radius: 20px;
  padding: 30px 25px;
  text-align: center;
  border: 1px solid var(--border);
  transition: var(--transition);
  position: relative;
  overflow: hidden;
}
.discount-card:hover { transform: translateY(-8px); box-shadow: var(--shadow-hover); }
.discount-card h3 { font-size: 1.2rem; margin-bottom: 15px; color: var(--primary); }
.discount-card .code {
  font-size: 1.3rem;
  font-weight: 800;
  letter-spacing: 1px;
  color: var(--text);
  background: var(--bg-alt);
  padding: 10px 20px;
  border-radius: 12px;
  display: inline-block;
  margin: 15px 0;
  font-family: monospace;
  direction: ltr;
}
.discount-card .discount-actions { display: flex; gap: 12px; justify-content: center; margin-top: 20px; }
.discount-card .discount-actions .copy-btn {
  padding: 10px 20px;
  border-radius: 50px;
  background: var(--primary-gradient);
  color: white;
  border: none;
  font-weight: 700;
  cursor: pointer;
  transition: var(--transition);
  font-size: 0.9rem;
}
.discount-card .discount-actions .activate-btn {
  padding: 10px 20px;
  border-radius: 50px;
  background: transparent;
  color: var(--primary);
  border: 2px solid var(--primary);
  font-weight: 700;
  cursor: pointer;
  transition: var(--transition);
  text-decoration: none;
  font-size: 0.9rem;
}
.discount-card .discount-actions .activate-btn:hover {
  background: var(--primary-gradient);
  color: white;
  border-color: transparent;
}

/* ===== Creators Tools ===== */
.tools-section { padding: 80px 0; }
.tools-horizontal-grid {
  display: flex;
  justify-content: center;
  flex-wrap: wrap;
  gap: 20px;
}
.tool-squircle {
  width: 120px; height: 120px;
  background: var(--card-bg);
  border-radius: 30px;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  text-decoration: none;
  transition: all 0.4s cubic-bezier(0.175,0.885,0.32,1.275);
  border: 1px solid var(--border);
  box-shadow: var(--shadow);
}
.tool-squircle:hover {
  transform: translateY(-8px) scale(1.05);
  box-shadow: var(--shadow-hover);
  border-color: var(--primary);
}
.tool-squircle .tool-icon {
  font-size: 2rem;
  color: var(--primary);
  margin-bottom: 10px;
  transition: var(--transition);
}
.tool-squircle:hover .tool-icon { transform: scale(1.1) rotate(5deg); color: var(--secondary); }
.tool-squircle .tool-name { font-size: 0.8rem; font-weight: 700; color: var(--text); text-align: center; }

/* ===== Theme Detector Game ===== */
.theme-detector-game {
  padding: 80px 0;
  background: var(--bg-alt);
  position: relative;
}
.quest-banner {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 20px 30px;
  background: var(--primary-gradient);
  border-radius: 20px;
  color: white;
  margin-bottom: 30px;
}
.quest-banner h2 { font-size: 1.3rem; color: white; }
.live-counter { display: flex; align-items: center; gap: 8px; font-size: 0.9rem; }
.pulse-dot {
  width: 10px; height: 10px;
  background: #22c55e;
  border-radius: 50%;
  animation: pulse 2s infinite;
}
@keyframes pulse {
  0%, 100% { transform: scale(1); opacity: 1; }
  50% { transform: scale(1.5); opacity: 0.5; }
}
.mission-card {
  background: var(--card-bg);
  border-radius: 24px;
  padding: 40px;
  text-align: center;
  box-shadow: var(--shadow);
  max-width: 600px;
  margin: 0 auto;
  border: 1px solid var(--border);
}
.mission-card h3 { font-size: 1.5rem; color: var(--primary); margin-bottom: 15px; }
.mission-card p { color: var(--text-light); margin-bottom: 25px; }
.game-buttons { display: flex; gap: 15px; justify-content: center; flex-wrap: wrap; }
.game-btn {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 14px 28px;
  border-radius: 50px;
  border: none;
  font-weight: 700;
  font-size: 0.95rem;
  cursor: pointer;
  transition: var(--transition);
}
.chrome-btn { background: #4285F4; color: white; }
.edge-btn { background: #0078D7; color: white; }
.game-btn:hover { transform: translateY(-3px); box-shadow: 0 8px 20px rgba(0,0,0,0.2); }
.scarcity-notice {
  margin-top: 20px;
  padding: 12px;
  background: rgba(239,68,68,0.1);
  border-radius: 12px;
  color: #ef4444;
  font-size: 0.9rem;
}

/* ===== Contact ===== */
.contact-section { padding: 80px 0; }
.contact-grid-wrapper {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 40px;
}
.contact-card-modern, .contact-form-card {
  background: var(--card-bg);
  border-radius: 24px;
  padding: 35px;
  box-shadow: var(--shadow);
  border: 1px solid var(--border);
}
.contact-card-modern .contact-header h2,
.contact-form-card .contact-header h2 { font-size: 1.5rem; color: var(--primary); margin-bottom: 8px; }
.contact-card-modern .contact-header p,
.contact-form-card .contact-header p { color: var(--text-light); font-size: 0.95rem; margin-bottom: 25px; }
.contact-list { display: flex; flex-direction: column; gap: 15px; }
.contact-item {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 15px 20px;
  background: var(--bg-alt);
  border-radius: 14px;
  transition: var(--transition);
}
.contact-item:hover { transform: translateX(-5px); }
.contact-item .contact-text h3 { font-size: 0.95rem; color: var(--text); margin-bottom: 3px; }
.contact-item .contact-text span { font-size: 0.85rem; color: var(--text-light); }
.contact-item .contact-icon-box {
  width: 45px; height: 45px;
  border-radius: 12px;
  background: rgba(var(--primary-rgb), 0.1);
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 1.2rem;
  color: var(--primary);
}
.whatsapp-full-btn {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 10px;
  width: 100%;
  padding: 16px;
  margin-top: 25px;
  border-radius: 14px;
  background: #25D366;
  color: white !important;
  font-weight: 700;
  font-size: 1.1rem;
  transition: var(--transition);
  text-decoration: none;
}
.whatsapp-full-btn:hover { transform: translateY(-3px); box-shadow: 0 10px 25px rgba(37,211,102,0.4); }
.form-tabs {
  display: flex;
  gap: 10px;
  margin-bottom: 25px;
}
.form-tab {
  flex: 1;
  padding: 12px;
  border-radius: 12px;
  border: 2px solid var(--border);
  background: transparent;
  color: var(--text-light);
  font-weight: 700;
  font-size: 0.9rem;
  cursor: pointer;
  transition: var(--transition);
  font-family: inherit;
}
.form-tab.active {
  border-color: var(--primary);
  background: rgba(var(--primary-rgb), 0.1);
  color: var(--primary);
}
.form-group { margin-bottom: 20px; }
.form-group label { display: block; font-weight: 600; margin-bottom: 8px; color: var(--text); font-size: 0.9rem; }
.form-group input,
.form-group textarea,
.form-group select {
  width: 100%;
  padding: 14px 16px;
  border: 2px solid var(--border);
  border-radius: 14px;
  font-size: 1rem;
  font-family: inherit;
  background: var(--bg);
  color: var(--text);
  transition: var(--transition);
}
.form-group input:focus,
.form-group textarea:focus,
.form-group select:focus {
  outline: none;
  border-color: var(--primary);
  box-shadow: 0 0 0 4px rgba(var(--primary-rgb), 0.1);
}
.form-group textarea { resize: vertical; min-height: 100px; }

/* ===== Help Section ===== */
.help-section { padding: 80px 0; background: var(--bg-alt); }
.help-section h2 { text-align: center; font-size: 2.2rem; color: var(--primary); margin-bottom: 50px; }
.help-cards { display: grid; grid-template-columns: repeat(auto-fill, minmax(300px, 1fr)); gap: 30px; }
.help-card {
  background: var(--card-bg);
  border-radius: 24px;
  padding: 35px 30px;
  box-shadow: var(--shadow);
  transition: var(--transition);
  border: 1px solid var(--border);
}
.help-card:hover { transform: translateY(-10px); box-shadow: var(--shadow-hover); }
.help-card-icon {
  width: 60px; height: 60px;
  border-radius: 16px;
  background: rgba(var(--primary-rgb), 0.1);
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 1.5rem;
  color: var(--primary);
  margin-bottom: 20px;
  transition: var(--transition);
}
.help-card:hover .help-card-icon { background: var(--primary-gradient); color: white; transform: rotate(5deg); }
.help-card h3 { font-size: 1.2rem; color: var(--primary); margin-bottom: 12px; }
.help-card p { color: var(--text-light); font-size: 0.95rem; line-height: 1.7; margin-bottom: 20px; }
.help-card-features { display: flex; flex-direction: column; gap: 10px; }
.help-card-features span {
  display: flex;
  align-items: center;
  gap: 8px;
  font-size: 0.9rem;
  color: var(--text);
}

/* ===== Vision & Mission ===== */
.vision-mission-content-centered {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 30px;
  max-width: 900px;
  margin: 0 auto;
}
.vision-box, .mission-box {
  background: var(--card-bg);
  border-radius: 20px;
  padding: 35px;
  text-align: center;
  box-shadow: var(--shadow);
  border: 1px solid var(--border);
  transition: var(--transition);
}
.vision-box:hover, .mission-box:hover { transform: translateY(-8px); box-shadow: var(--shadow-hover); }
.vision-box h3, .mission-box h3 { font-size: 1.3rem; color: var(--primary); margin: 15px 0 10px; }
.vision-box p, .mission-box p { color: var(--text-light); font-size: 0.95rem; line-height: 1.7; }
.values-grid-centered {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(230px, 1fr));
  gap: 25px;
  max-width: 1000px;
  margin: 40px auto 0;
}
.value-card {
  background: var(--card-bg);
  border-radius: 18px;
  padding: 30px;
  text-align: center;
  box-shadow: var(--shadow);
  border: 1px solid var(--border);
  transition: var(--transition);
}
.value-card:hover { transform: translateY(-6px); box-shadow: var(--shadow-hover); }
.value-card h3 { font-size: 1.1rem; color: var(--primary); margin: 12px 0 8px; }
.value-card p { color: var(--text-light); font-size: 0.9rem; line-height: 1.6; }

/* ===== CTA ===== */
.cta-section { padding: 80px 0; background: var(--bg-alt); }
.cta-content-centered {
  text-align: center;
  max-width: 650px;
  margin: 0 auto;
}
.cta-content-centered h2 { font-size: 2rem; color: var(--primary); margin-bottom: 15px; }
.cta-content-centered p { color: var(--text-light); font-size: 1.05rem; margin-bottom: 30px; }

/* ===== Floating WhatsApp ===== */
.floating-whatsapp {
  position: fixed;
  bottom: 25px;
  left: 25px;
  width: 56px; height: 56px;
  background: #25D366;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  color: white !important;
  font-size: 1.5rem;
  box-shadow: 0 4px 15px rgba(37,211,102,0.4);
  z-index: 999;
  transition: var(--transition);
}
.floating-whatsapp:hover {
  transform: scale(1.1) translateY(-5px);
  box-shadow: 0 8px 25px rgba(37,211,102,0.6);
}

/* ===== Scrolling Logos ===== */
.scrolling-logos-container {
  overflow: hidden;
  padding: 30px 0;
}
.scrolling-logos {
  display: flex;
  gap: 50px;
  animation: scrollLogos 20s linear infinite;
  width: max-content;
}
.scrolling-logos .logo-item {
  flex: 0 0 auto;
  padding: 10px 30px;
  background: rgba(var(--primary-rgb), 0.05);
  border-radius: 12px;
  border: 1px solid var(--border);
  font-weight: 700;
  color: var(--text-light);
  font-size: 1.1rem;
}
@keyframes scrollLogos {
  0% { transform: translateX(0); }
  100% { transform: translateX(-50%); }
}

/* ===== Back to Top ===== */
.back-to-top {
  position: fixed;
  bottom: 25px;
  right: 25px;
  width: 50px; height: 50px;
  background: var(--primary-gradient);
  color: white;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 1.3rem;
  cursor: pointer;
  z-index: 999;
  opacity: 0;
  visibility: hidden;
  transition: var(--transition);
  border: none;
  box-shadow: 0 5px 15px rgba(var(--primary-rgb), 0.4);
}
.back-to-top.show { opacity: 1; visibility: visible; }
.back-to-top:hover { transform: translateY(-5px); }

/* ===== Blogger Post Styles ===== */
.post { margin-bottom: 40px; }
.post-title { font-size: 2rem; color: var(--primary); margin-bottom: 15px; }
.post-body { color: var(--text); line-height: 1.9; font-size: 1rem; }
.post-body h2, .post-body h3 { color: var(--primary); margin: 25px 0 15px; }
.post-body p { margin-bottom: 15px; }
.post-body img { border-radius: 12px; margin: 20px 0; }
.post-meta {
  display: flex;
  gap: 20px;
  color: var(--text-light);
  font-size: 0.85rem;
  margin-bottom: 20px;
  padding-bottom: 20px;
  border-bottom: 1px solid var(--border);
}
.post-footer {
  margin-top: 30px;
  padding-top: 20px;
  border-top: 1px solid var(--border);
}

/* ===== Sidebar Widgets ===== */
.widget { margin-bottom: 40px; }
.widget h2 {
  font-size: 1.3rem;
  color: var(--primary);
  margin-bottom: 20px;
  padding-bottom: 10px;
  border-bottom: 3px solid var(--primary);
}
.PopularPosts .item-title { font-size: 0.95rem; font-weight: 600; margin-bottom: 5px; }
.PopularPosts .item-snippet { color: var(--text-light); font-size: 0.85rem; }

/* ===== Footer ===== */
.footer {
  background: #14102a;
  color: white;
  padding: 70px 0 20px;
  position: relative;
  overflow: hidden;
}
.footer::before {
  content: '';
  position: absolute;
  inset: 0;
  background: url("data:image/svg+xml,%3Csvg width='60' height='60' viewBox='0 0 60 60' xmlns='http://www.w3.org/2000/svg'%3E%3Cg fill='none' fill-rule='evenodd'%3E%3Cg fill='%239C92AC' fill-opacity='0.05'%3E%3Cpath d='M36 34v-4h-2v4h-4v2h4v4h2v-4h4v-2h-4zm0-30V0h-2v4h-4v2h4v4h2V6h4V4h-4zM6 34v-4H4v4H0v2h4v4h2v-4h4v-2H6zM6 4V0H4v4H0v2h4v4h2V6h4V4H6z'/%3E%3C/g%3E%3C/g%3E%3C/svg%3E");
  opacity: 0.3;
  z-index: 0;
}
.footer-content {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));
  gap: 40px;
  margin-bottom: 40px;
  position: relative;
  z-index: 1;
}
.footer h3 {
  font-size: 1.2rem;
  margin-bottom: 20px;
  position: relative;
  color: white;
}
.footer h3::after {
  content: '';
  position: absolute;
  bottom: -8px;
  right: 0;
  width: 40px;
  height: 2px;
  background: var(--secondary);
}
.footer-about p { color: rgba(255,255,255,0.7); font-size: 0.9rem; line-height: 1.8; }
.footer-links ul { display: flex; flex-direction: column; gap: 12px; }
.footer-links ul li a { color: rgba(255,255,255,0.7); transition: var(--transition); font-size: 0.9rem; }
.footer-links ul li a:hover { color: var(--secondary); padding-right: 5px; }
.footer-contact ul li {
  display: flex;
  align-items: center;
  gap: 10px;
  color: rgba(255,255,255,0.7);
  font-size: 0.9rem;
  margin-bottom: 12px;
}
.footer-social {
  display: flex;
  gap: 10px;
  margin-top: 20px;
  flex-wrap: wrap;
}
.footer-social a {
  width: 38px; height: 38px;
  border-radius: 50%;
  background: rgba(255,255,255,0.1);
  display: flex;
  align-items: center;
  justify-content: center;
  color: white;
  transition: var(--transition);
  text-decoration: none;
  font-size: 0.9rem;
}
.footer-social a:hover { background: var(--secondary); transform: translateY(-3px); color: white; }
.footer-bottom {
  text-align: center;
  padding-top: 20px;
  border-top: 1px solid rgba(255,255,255,0.1);
  position: relative;
  z-index: 1;
}
.footer-bottom p { font-size: 0.85rem; color: rgba(255,255,255,0.6); }

/* ===== Responsive ===== */
@media (max-width: 768px) {
  .hero-content h1 { font-size: 2.2rem; }
  .hero-content p { font-size: 1rem; }
  .section-title h2 { font-size: 1.8rem; }
  .contact-grid-wrapper { grid-template-columns: 1fr; }
  .vision-mission-content-centered { grid-template-columns: 1fr; }
  .stores-grid { grid-template-columns: repeat(2, 1fr); }
  .stores-actions { flex-direction: column; }
  .action-btn { width: 100%; justify-content: center; }
  .quest-banner { flex-direction: column; gap: 10px; text-align: center; }
  .stat-number { font-size: 2.2rem; }
  .stats-grid { grid-template-columns: repeat(2, 1fr); }
  .partners-grid { grid-template-columns: repeat(3, 1fr); }
  .section { padding: 60px 0; }
  .floating-whatsapp { width: 48px; height: 48px; font-size: 1.2rem; bottom: 20px; left: 20px; }
  .back-to-top { width: 44px; height: 44px; bottom: 20px; right: 20px; }
}
@media (max-width: 480px) {
  .hero-content h1 { font-size: 1.8rem; }
  .stats-grid { grid-template-columns: 1fr; }
  .stores-grid { grid-template-columns: repeat(2, 1fr); }
  .partners-grid { grid-template-columns: repeat(2, 1fr); }
  .tool-squircle { width: 100px; height: 100px; }
  .services-grid { grid-template-columns: 1fr; }
  .portfolio-scroll { padding: 15px 0 25px; gap: 15px; }
  .portfolio-item-snap { flex: 0 0 260px; height: 230px; }
  .discounts-grid { grid-template-columns: 1fr; }
  .discount-card { padding: 20px; }
  .section-title h2 { font-size: 1.5rem; }
  .section-title h2::after { width: 40px; }
  .help-grid { grid-template-columns: 1fr; }
}
@media (pointer: coarse) {
  .nav-links li a { padding: 12px 20px; min-height: 44px; display: flex; align-items: center; }
  .theme-toggle, .mobile-toggle { width: 44px; height: 44px; }
  .portfolio-item-snap { min-height: 44px; }
  .store-link-card { padding: 20px 15px; }
}

/* ===== Page Header (for inner pages) ===== */
.page-header {
  padding: 140px 0 30px;
  text-align: center;
  background: linear-gradient(135deg, rgba(var(--primary-rgb),0.1), rgba(var(--primary-rgb),0.05));
  border-radius: 0 0 var(--radius-lg) var(--radius-lg);
  margin-bottom: 30px;
}
.page-header h1 { font-size: 2.5rem; color: var(--primary); margin-bottom: 10px; }
.page-header p { color: var(--text-light); font-size: 1.05rem; }

/* ===== Tab Panels ===== */
.tab-panels { width: 100%; }
.tab-panel { display: none; }
.tab-panel.active { display: block; }
.tab-panel.active .hero-section { display: flex; }

/* Tab switching animation */
.tab-panel.active { animation: tabFadeIn 0.35s var(--ease-out-quart); will-change: transform, opacity; }
@keyframes tabFadeIn {
  from { opacity: 0; transform: translateY(16px); }
  to { opacity: 1; transform: translateY(0); }
}
.tab-panel.active .hero-section { animation: heroFadeIn 0.5s var(--ease-out-expo); }
@keyframes heroFadeIn {
  from { opacity: 0; transform: translateY(24px) scale(0.98); }
  to { opacity: 1; transform: translateY(0) scale(1); }
}
@media (prefers-reduced-motion: reduce) {
  .tab-panel.active, .tab-panel.active .hero-section { animation: none; }
}

/* Blog Styles */
.blog-container {
  padding: 140px 0 60px;
  max-width: 1200px;
  margin: 0 auto;
  padding-left: 20px;
  padding-right: 20px;
}
.blog-layout { display: flex; gap: 40px; align-items: flex-start; }
.blog-posts { flex: 1; min-width: 0; }
.blog-sidebar { width: 320px; flex-shrink: 0; }
.blog-post-card {
  background: var(--card-bg);
  border-radius: var(--radius-lg);
  padding: 30px;
  margin-bottom: 25px;
  border: 1px solid var(--border);
  transition: var(--transition);
}
.blog-post-card:hover { box-shadow: var(--shadow-hover); transform: translateY(-3px); }
.blog-post-card .post-title { font-size: 1.5rem; margin-bottom: 12px; }
.blog-post-card .post-title a { color: var(--text); }
.blog-post-card .post-title a:hover { color: var(--primary); }
.blog-post-meta { display: flex; gap: 15px; flex-wrap: wrap; margin-bottom: 15px; font-size: 0.85rem; color: var(--text-light); }
.blog-post-meta span { display: flex; align-items: center; gap: 5px; }
.blog-post-body { color: var(--text); line-height: 1.9; font-size: 1rem; }
.blog-post-body img { max-width: 100%; border-radius: var(--radius); margin: 15px 0; }
.read-more {
  display: inline-block;
  margin-top: 15px;
  padding: 10px 25px;
  background: var(--primary-gradient);
  color: white;
  border-radius: 50px;
  font-weight: 600;
  font-size: 0.9rem;
  transition: var(--transition);
}
.read-more:hover { transform: translateY(-2px); box-shadow: var(--shadow-hover); color: white; }
.blog-pagination {
  display: flex;
  justify-content: center;
  gap: 10px;
  margin: 40px 0;
}
.blog-pagination a {
  padding: 10px 20px;
  background: var(--card-bg);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  color: var(--text);
  font-weight: 500;
  transition: var(--transition);
}
.blog-pagination a:hover { background: var(--primary-gradient); color: white; border-color: transparent; }

/* Single Post */
.blog-single { padding: 140px 0 60px; max-width: 800px; margin: 0 auto; padding-left: 20px; padding-right: 20px; }
.blog-single .post-title { font-size: 2rem; margin-bottom: 15px; color: var(--text); }
.blog-single .blog-post-body { font-size: 1.05rem; }

/* Comments */
.comments-section { margin-top: 50px; padding-top: 30px; border-top: 1px solid var(--border); }
.comments-section h3 { font-size: 1.3rem; margin-bottom: 20px; color: var(--text); }
.comments-section .comment { padding: 20px; background: var(--bg-alt); border-radius: var(--radius); margin-bottom: 15px; }
.comments-section .comment-header { display: flex; align-items: center; gap: 10px; margin-bottom: 10px; }
.comments-section .comment-author { font-weight: 700; color: var(--text); }
.comments-section .comment-date { font-size: 0.8rem; color: var(--text-light); }
.comments-section .comment-body { color: var(--text); line-height: 1.7; }

/* Sidebar */
.blog-sidebar .sidebar-widget {
  background: var(--card-bg);
  border: 1px solid var(--border);
  border-radius: var(--radius-lg);
  padding: 25px;
  margin-bottom: 25px;
}
.blog-sidebar .sidebar-widget h3 {
  font-size: 1.1rem;
  margin-bottom: 15px;
  padding-bottom: 10px;
  border-bottom: 2px solid var(--primary);
  color: var(--text);
}
.blog-sidebar .sidebar-widget ul { list-style: none; padding: 0; }
.blog-sidebar .sidebar-widget ul li { margin-bottom: 8px; }
.blog-sidebar .sidebar-widget ul li a {
  color: var(--text-light);
  padding: 5px 0;
  display: block;
  transition: var(--transition);
}
.blog-sidebar .sidebar-widget ul li a:hover { color: var(--primary); padding-right: 5px; }

@media (max-width: 768px) {
  .blog-layout { flex-direction: column; }
  .blog-sidebar { width: 100%; }
  .blog-post-card .post-title { font-size: 1.2rem; }
  .blog-single .post-title { font-size: 1.5rem; }
}

