            //
            /* =====================================
               قالب بلوجر احترافي - مصمم متاجر سلة و زد ورمز
               جميع الحقوق محفوظة Ali Ahmed © <data:blog.title/>
               ===================================== */

            // تهيئة القالب
            document.addEventListener('DOMContentLoaded', function() {
              initTheme();
              initMobileMenu();
              initScrollHeader();
              initStatsCounter();
              initBackToTop();
              initYear();
              initActiveNav();
              initTabSwipe();
            });

            // ===== نظام الألوان =====
            function initTheme() {
              const saved = localStorage.getItem('blogger_theme');
              if (saved === 'dark') {
                document.documentElement.setAttribute('data-theme', 'dark');
              } else if (saved === 'light') {
                document.documentElement.setAttribute('data-theme', 'light');
              } else if (window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches) {
                document.documentElement.setAttribute('data-theme', 'dark');
              }
              const btn = document.querySelector('.theme-toggle');
              if (btn) btn.textContent = (document.documentElement.getAttribute('data-theme') === 'dark') ? '☀️' : '🌙';
            }

            function toggleTheme() {
              const current = document.documentElement.getAttribute('data-theme');
              const next = current === 'dark' ? 'light' : 'dark';
              document.documentElement.setAttribute('data-theme', next);
              localStorage.setItem('blogger_theme', next);
              const btn = document.querySelector('.theme-toggle');
              if (btn) btn.textContent = next === 'dark' ? '☀️' : '🌙';
            }

            // ===== القائمة المتنقلة =====
            function initMobileMenu() {
              const toggle = document.querySelector('.mobile-toggle');
              const nav = document.querySelector('.nav');
              if (!toggle || !nav) return;

              toggle.addEventListener('click', function() {
                nav.classList.toggle('active');
                toggle.textContent = nav.classList.contains('active') ? '✕' : '☰';
              });

              nav.querySelectorAll('a').forEach(function(link) {
                link.addEventListener('click', function() {
                  nav.classList.remove('active');
                  toggle.textContent = '☰';
                });
              });
            }

            // ===== تأثير التمرير للهيدر =====
            function initScrollHeader() {
              window.addEventListener('scroll', function() {
                const header = document.querySelector('.header');
                if (!header) return;
                if (window.scrollY > 50) {
                  header.classList.add('scrolled');
                } else {
                  header.classList.remove('scrolled');
                }
              });
            }

            // ===== عداد الإحصائيات المتحرك =====
            function initStatsCounter() {
              const counters = document.querySelectorAll('.stat-number');
              if (!counters.length) return;

              const observer = new IntersectionObserver(function(entries) {
                entries.forEach(function(entry) {
                  if (entry.isIntersecting) {
                    const target = parseInt(entry.target.getAttribute('data-target'));
                    animateCounter(entry.target, target);
                    observer.unobserve(entry.target);
                  }
                });
              }, { threshold: 0.5 });

              counters.forEach(function(counter) {
                observer.observe(counter);
              });
            }

            function animateCounter(el, target) {
              let current = 0;
              const increment = Math.ceil(target / 40);
              const timer = setInterval(function() {
                current += increment;
                if (current >= target) {
                  current = target;
                  clearInterval(timer);
                }
                el.textContent = current;
              }, 40);
            }

            // ===== زر العودة للأعلى =====
            function initBackToTop() {
              const btn = document.querySelector('.back-to-top');
              if (!btn) return;

              window.addEventListener('scroll', function() {
                if (window.scrollY > 400) {
                  btn.classList.add('show');
                } else {
                  btn.classList.remove('show');
                }
              });

              btn.addEventListener('click', function() {
                window.scrollTo({ top: 0, behavior: 'smooth' });
              });
            }

            // ===== تحديث السنة =====
            function initYear() {
              const el = document.getElementById('currentYear');
              if (el) el.textContent = new Date().getFullYear();
            }

            // ===== نسخ النص =====
            function copyCode(code, btn) {
              function done() {
                const orig = btn.textContent;
                btn.textContent = '✅ تم النسخ';
                btn.style.background = '#10B981';
                btn.disabled = true;
                setTimeout(function() {
                  btn.textContent = orig;
                  btn.style.background = '';
                  btn.disabled = false;
                }, 2000);
              }
              if (navigator.clipboard && navigator.clipboard.writeText) {
                navigator.clipboard.writeText(code).then(done, function() {
                  fallbackCopy(code, done);
                });
              } else {
                fallbackCopy(code, done);
              }
            }
            function fallbackCopy(text, callback) {
              var ta = document.createElement('textarea');
              ta.value = text;
              ta.style.position = 'fixed'; ta.style.left = '-9999px';
              document.body.appendChild(ta);
              ta.select();
              document.execCommand('copy');
              document.body.removeChild(ta);
              if (callback) callback();
            }

            // ===== إرسال واتساب =====
            function sendToWhatsApp(event) {
              event.preventDefault();
              const name = document.getElementById('contact-name');
              const email = document.getElementById('contact-email');
              const message = document.getElementById('contact-message');
              const storeUrl = document.getElementById('contact-store-url');
              const serviceType = document.getElementById('contact-service-type');

              let whatsappMessage = 'مرحباً، ';
              const isQuote = document.getElementById('quote-fields') ? document.getElementById('quote-fields').style.display !== 'none' : true;

              if (isQuote) {
                whatsappMessage += 'أرغب في طلب تسعير خدمة.\n\n';
              } else {
                whatsappMessage += 'لدي استفسار عام.\n\n';
              }

              whatsappMessage += '📋 *بياناتي:*\n';
              whatsappMessage += '👤 الاسم: ' + (name ? name.value : '') + '\n';
              whatsappMessage += '📧 البريد: ' + (email ? email.value : '') + '\n';
              if (isQuote && storeUrl && storeUrl.value) {
                whatsappMessage += '🔗 رابط المتجر: ' + storeUrl.value + '\n';
              }
              if (isQuote && serviceType && serviceType.value) {
                whatsappMessage += '🛠️ نوع الخدمة: ' + serviceType.value + '\n';
              }
              if (message && message.value) {
                whatsappMessage += '\n📝 *الرسالة:*\n' + message.value;
              }

              window.open('https://wa.me/201002241591?text=' + encodeURIComponent(whatsappMessage), '_blank');
            }

            // ===== تبديل تبويب النموذج =====
            function switchFormTab(event, tabName) {
              const tabs = document.querySelectorAll('.form-tab');
              tabs.forEach(function(t) { t.classList.remove('active'); });
              if (event && event.currentTarget) event.currentTarget.classList.add('active');

              const quoteFields = document.getElementById('quote-fields');
              if (quoteFields) {
                quoteFields.style.display = tabName === 'quote' ? 'block' : 'none';
              }
            }

            // ===== نسخ روابط المتاجر =====
            function copyAllStoreLinks() {
              const links = document.querySelectorAll('.store-link-card');
              let text = '';
              links.forEach(function(link) {
                text += link.getAttribute('data-store') || link.href + '\n';
              });
              navigator.clipboard.writeText(text).then(function() {
                const toast = document.getElementById('copy-toast');
                if (toast) {
                  toast.classList.add('show');
                  setTimeout(function() { toast.classList.remove('show'); }, 3000);
                }
              });
            }

            // ===== مشاركة عبر واتساب =====
            function shareViaWhatsApp() {
              const links = document.querySelectorAll('.store-link-card');
              let text = '🏪 روابط متاجر Ali Ahmed Design:\n\n';
              links.forEach(function(link) {
                text += (link.getAttribute('data-store') || link.href) + '\n';
              });
              text += '\n✨ للتواصل: https://wa.me/201002241591';
              window.open('https://wa.me/?text=' + encodeURIComponent(text), '_blank');
            }

            // ===== تبديل التبويبات =====
            function switchTab(name) {
              var panels = document.querySelectorAll('.tab-panel');
              var tabs = document.querySelectorAll('.nav-links a');
              panels.forEach(function(p) { p.classList.remove('active'); });
              tabs.forEach(function(t) { t.classList.remove('active'); });
              var target = document.querySelector('.tab-panel[data-tab="' + name + '"], #panel-' + name);
              if (target) target.classList.add('active');
              var activeTab = document.querySelector('.nav-links a[onclick*="' + name + '"]');
              if (activeTab) activeTab.classList.add('active');
              window.scrollTo({ top: 0, behavior: 'smooth' });
              // إعادة تشغيل عدادات الإحصائيات عند العودة للرئيسية
              if (name === 'home') {
                setTimeout(function() {
                  document.querySelectorAll('.stat-number:not(.counted)').forEach(function(el) {
                    var target = parseInt(el.getAttribute('data-target'));
                    if (target && !isNaN(target)) {
                      el.classList.add('counted');
                      var current = 0;
                      var inc = Math.ceil(target / 40);
                      var timer = setInterval(function() {
                        current += inc;
                        if (current >= target) { current = target; clearInterval(timer); }
                        el.textContent = current;
                      }, 30);
                    }
                  });
                }, 350);
              }
            }

            // ===== تفعيل التاب النشط حسب الصفحة =====
            function initActiveNav() {
              var allTabs = document.querySelectorAll('.nav-links a');
              allTabs.forEach(function(t) { t.classList.remove('active'); });
              if (document.querySelector('.tab-panel')) {
                switchTab('home');
              } else if (window.location.pathname.indexOf('/search') === 0) {
                var blogTab = document.querySelector('.nav-links a[href="/search"]');
                if (blogTab) blogTab.classList.add('active');
              } else {
                var homeTab = document.querySelector('.nav-links a[href="/"]');
                if (homeTab) homeTab.classList.add('active');
              }
            }

            // ===== التنقل بالسحب (Swipe) للتبويبات =====
            function initTabSwipe() {
              var panels = document.querySelector('.tab-panels');
              if (!panels) return;
              var startX = 0, endX = 0;
              var tabs = ['home', 'services', 'about', 'portfolio', 'tools', 'discounts', 'contact'];
              panels.addEventListener('touchstart', function(e) {
                startX = e.changedTouches[0].screenX;
              }, { passive: true });
              panels.addEventListener('touchend', function(e) {
                endX = e.changedTouches[0].screenX;
                var diff = startX - endX;
                if (Math.abs(diff) < 50) return;
                var current = document.querySelector('.tab-panel.active');
                if (!current) return;
                var idx = -1;
                var id = current.id || '';
                var dataTab = current.getAttribute('data-tab') || '';
                var currentName = id.replace('panel-', '') || dataTab;
                tabs.forEach(function(t, i) { if (t === currentName) idx = i; });
                if (idx === -1) return;
                if (diff > 0 && idx < tabs.length - 1) {
                  switchTab(tabs[idx + 1]);
                } else if (diff < 0 && idx > 0) {
                  switchTab(tabs[idx - 1]);
                }
              }, { passive: true });
            }

            // ===== دعم روابط التبويبات (هاش لينكس) =====
            document.addEventListener('click', function(e) {
              var a = e.target.closest('a[href^="#"]');
              if (!a) return;
              var section = a.getAttribute('href').substring(1);
              var tabMap = { home:'home', services:'services', about:'about', portfolio:'portfolio', tools:'tools', discounts:'discounts', contact:'contact' };
              if (tabMap[section]) {
                e.preventDefault();
                switchTab(tabMap[section]);
              }
            });

            //


